CREATE TYPE "RoomStatus" AS ENUM ('AVAILABLE', 'IN_SERVICE', 'PAUSED', 'CLOSED', 'UNAVAILABLE');
CREATE TYPE "UserRole" AS ENUM ('ADMIN');
CREATE TABLE "User" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"email" TEXT NOT NULL,"passwordHash" TEXT NOT NULL,"role" "UserRole" NOT NULL DEFAULT 'ADMIN',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "User_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Doctor" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"specialty" TEXT NOT NULL,"crm" TEXT,"phone" TEXT,"email" TEXT,"photoUrl" TEXT,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Doctor_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Room" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"floor" TEXT,"status" "RoomStatus" NOT NULL DEFAULT 'AVAILABLE',"doctorId" TEXT,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Room_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Device" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"deviceCode" TEXT NOT NULL,"pairingCode" TEXT NOT NULL,"roomId" TEXT,"isOnline" BOOLEAN NOT NULL DEFAULT false,"lastSeenAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Device_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AuditLog" ("id" TEXT NOT NULL,"userId" TEXT,"action" TEXT NOT NULL,"entity" TEXT NOT NULL,"entityId" TEXT,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AuditLog_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "User_email_key" ON "User"("email");
CREATE UNIQUE INDEX "Device_deviceCode_key" ON "Device"("deviceCode");
CREATE UNIQUE INDEX "Device_pairingCode_key" ON "Device"("pairingCode");
ALTER TABLE "Room" ADD CONSTRAINT "Room_doctorId_fkey" FOREIGN KEY ("doctorId") REFERENCES "Doctor"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "Device" ADD CONSTRAINT "Device_roomId_fkey" FOREIGN KEY ("roomId") REFERENCES "Room"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "AuditLog" ADD CONSTRAINT "AuditLog_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE;
